// CLX Lead Scoring v2 — Parse Scoring Response

const response = $input.item.json;
const lead = $('Split In Batches').first().json;

const rawText = (response && response.content && response.content[0] && response.content[0].text) || '';

let scoring;
try {
  const cleaned = rawText.replace(/```json/gi, '').replace(/```/g, '').trim();
  scoring = JSON.parse(cleaned);
} catch (e) {
  scoring = {
    lead_score: 0,
    priority_level: 'Low',
    decision_maker_probability: 'Low',
    company_size_estimate: 'SMB',
    scoring_reason: 'Manual review needed — AI parse error: ' + e.message
  };
}

const now = new Date().toISOString();

return {
  json: {
    id: lead.id,
    lead_score: typeof scoring.lead_score === 'number' ? scoring.lead_score : 0,
    priority_level: scoring.priority_level || 'Low',
    decision_maker_probability: scoring.decision_maker_probability || 'Low',
    company_size_estimate: scoring.company_size_estimate || 'SMB',
    scoring_reason: scoring.scoring_reason || '',
    lead_status: 'Scored',
    updated_at: now
  }
};

// CLX Lead Scoring v2 — Prep Update Score

const item = $input.item.json;

const body = {
  p_lead_id: item.id,
  p_fields: {
    lead_score: item.lead_score,
    priority_level: item.priority_level,
    decision_maker_probability: item.decision_maker_probability,
    company_size_estimate: item.company_size_estimate,
    scoring_reason: item.scoring_reason,
    lead_status: 'Scored'
  }
};

console.log('PREP UPDATE:', JSON.stringify({ lead_id: item.id, status: body.p_fields.lead_status, score: item.lead_score }));

return { json: { ...item, rpc_body: JSON.stringify(body) } };
